        LoadedGeneration loaded = new LoadedGeneration(generation, classLoader, factory.open());
        LIVE.put(generation, loaded);
        return loaded;
    }

    long generation() {
        return generation;
    }

    PluginModule module() {
        return module;
    }

    @Override
    public void close() throws Exception {
        module.close();
        classLoader.close();
    }
